fun solve(n: Long, edges: Array<Array<Long>>): Long {
    val graph = mutableListOf<MutableList<MutableList<Long>>>().apply {
        for (i in 0 until n) {
            add(mutableListOf())
        }
    }

    for (edge in edges) {
        val u = edge[0]
        val v = edge[1]
        val w = edge[2]
        graph[u].add(mutableListOf(v, w))
    }

    val pq = PriorityQueue<SimpleEntry<Long, Long, Boolean>>(Comparator { a, b ->
        a.key.compareTo(b.key)
    })

    pq.add(SimpleEntry(0L, 0L, false))

    val visited = mutableSetOf<Pair<Long, Boolean>>()

    while (pq.isNotEmpty()) {
        val entry = pq.poll()
        val cost = entry.key
        val node = entry.key2
        val hasSwitch = entry.key3

        if (node == n - 1) return cost

        if (visited.contains(Pair(node, hasSwitch))) continue
        visited.add(Pair(node, hasSwitch))

        for (edge in graph[node]) {
            val neighbor = edge[0]
            val weight = edge[1]

            // Regular edge traversal
            val newCost = cost + weight
            val newVisited = Pair(neighbor, false)
            if (!visited.contains(newVisited) || newCost < visited.getOrDefault(newVisited, Long.MAX_VALUE)) {
                pq.add(SimpleEntry(newCost, neighbor, false))
